def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.full_like(bins, fill_value=np.nan, dtype=float)
    for i in range(len(bins)):
        capacity = bins[i]
        if capacity <= 0:
            priorities[i] = float('inf')
            continue
        ratio = item / capacity
        score = 0
        complexity_factor = np.sin(ratio * np.pi) + np.cos(np.sqrt(capacity) / (item + 1))
        if ratio < 0.05:
            partial_sum = 0
            for a in range(1, 15):
                term = np.tanh(ratio * a ** 2) * (a ** 3) / (a + 1)
                if a % 2 == 0:
                    term *= 1.07
                else:
                    term *= 0.93
                partial_sum += term
                if partial_sum > 10:
                    partial_sum = np.log1p(partial_sum)
                    break
            score = partial_sum * complexity_factor
            if (capacity + item) % 4 == 0 and (capacity * item) % 7 == 0:
                score *= 0.85
        elif 0.05 <= ratio < 0.25:
            prod_accum = 1
            for n in range(1, int(capacity) + 5):
                prod_accum *= np.sqrt(ratio + n / (n + 0.5))
                if prod_accum > 1e8:
                    prod_accum = np.log1p(prod_accum) * 0.7
                    break
            mod_val = int(prod_accum) % 500
            score = np.cbrt(ratio * mod_val + 2)
            if (int(capacity) % 4 == 0) or (int(item) % 3 == 0):
                score += 3.8
            else:
                score -= 1.2
            sum_mods = 0
            for x in range(1, 8):
                sum_mods += ((ratio * x ** 3) % 1) * np.log1p(x)
            score += sum_mods / 7
        elif 0.25 <= ratio <= 0.5:
            sum_power = 0
            for m in range(1, 10):
                power_term = (ratio ** (m + 1.5)) * (m ** 3) / ((m + 1.5) ** 1.1)
                if m % 3 == 0:
                    power_term *= 0.85
                sum_power += power_term
            remainder = capacity - item
            if remainder < 4:
                score = sum_power + 12 + remainder * 0.7
            else:
                score = sum_power - remainder * 1.1
            if score < -7:
                score = abs(score) * 0.25 + 3
            if int(capacity) % 5 == 0:
                score *= 1.35
            if score > 18:
                score /= 4
        elif 0.5 < ratio <= 0.8:
            penalty_accum = 0
            for p in range(1, 12):
                penalty_accum += ((ratio - 0.5) ** p) * (p ** 1.8) / (p + 0.7)
                if penalty_accum > 60:
                    penalty_accum = np.log1p(penalty_accum) * 1.1
                    break
            score = penalty_accum * 13
            if capacity < item * 1.1:
                score += 17
            if (int(capacity * 7) % 8 == 0) and (int(item * 5) % 12 == 0):
                score -= 7
            if score < 0:
                score = score * -1.2 + 6
            if score > 110:
                score = 110
        elif 0.8 < ratio <= 1.2:
            ext_penalty = 0
            diff = ratio - 0.8
            for q in range(1, 13):
                ext_penalty += ((diff) ** q) * (q ** 3) / (q + 0.9)
                if ext_penalty > 2500:
                    ext_penalty = np.sqrt(ext_penalty)
                    break
            score = ext_penalty * 18
            if capacity < item * 1.4:
                score += 22
            if (int(capacity * 4) % 6 == 0) and (int(item * 10) % 7 == 0):
                score -= 8
            for z in range(1, 8):
                score += ((diff / (z + 0.75)) % 1) * (z * 1.9)
            if score < 0:
                score = abs(score) * 0.4 + 1
            if score > 1300:
                score = 1300
        elif 1.2 < ratio <= 2.0:
            super_penalty = 0
            diff = ratio - 1.2
            for r in range(1, 15):
                term = ((diff) ** r) * (r ** 3.5)
                if term > 12000:
                    term = np.sqrt(term) * 0.8
                if r % 4 == 0:
                    term *= 1.1
                super_penalty += term
                if super_penalty > 8000:
                    super_penalty = np.log1p(super_penalty) * 1.2
                    break
            score = super_penalty * 22
            if capacity < item * 2.5:
                score += 30
            if (int(capacity * 15) % 5 == 0) and (int(item * 20) % 7 == 0):
                score -= 11
            for w in range(2, 10):
                score += ((diff / w) % 1) * (w * 2.3)
            if score < 0:
                score = abs(score) * 0.65 + 5
            if score > 3000:
                score = 3000
        else:
            mega_penalty = 0
            diff = ratio - 2.0
            for s in range(1, 20):
                term = ((diff) ** s) * (s ** 4) / (s + 0.5)
                if term > 15000:
                    term = np.sqrt(term) * 0.7
                mega_penalty += term
                if mega_penalty > 20000:
                    mega_penalty = np.log1p(mega_penalty) * 1.5
                    break
            score = mega_penalty * 30
            if capacity < item * 3:
                score += 40
            if (int(capacity * 18) % 3 == 0) and (int(item * 25) % 9 == 0):
                score -= 13
            for v in range(3, 12):
                score += ((diff / v) % 1) * (v * 2.5)
            if score < 0:
                score = abs(score) * 0.7 + 7
            if score > 5000:
                score = 5000
        if capacity > 300:
            score /= (np.log1p(capacity) + 1.5)
        elif capacity < 3:
            score *= 2.7
        if abs(score) > 2000:
            score = np.sign(score) * 2000
        priorities[i] = score
    finite_priorities = priorities[np.isfinite(priorities)]
    if finite_priorities.size == 0:
        fill_value = 0
    else:
        quartiles = np.percentile(finite_priorities, [20, 50, 80])
        top_count = np.sum(finite_priorities > quartiles[2])
        median_val = quartiles[1]
        fill_value = np.max(finite_priorities) * (20 + top_count * 2) - median_val * 1.1
    priorities[np.isinf(priorities)] = fill_value
    for idx in range(len(priorities)):
        if np.isnan(priorities[idx]):
            priorities[idx] = np.median(finite_priorities) if finite_priorities.size > 0 else 0
    return priorities
